var surah029 = {
  number: 29,
  nameArabic: "al-'Ankabut",
  nameEnglish: "Al-Ankabut",
  meaning: "The Spider",
  totalAyahs: 69,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laaam-Meeem", english: "L. M", romanUrdu: "Alif Laam Meem" },
    { number: 2, arabic: "أَحَسِبَ ٱلنَّاسُ أَن يُتْرَكُوٓا۟ أَن يَقُولُوٓا۟ ءَامَنَّا وَهُمْ لَا يُفْتَنُونَ", transliteration: "Ahasiba alnnasu an yutrakoo an yaqooloo amanna wahum la yuftanoona", transliterationB: "Ahasiban naasu anyu yutrakooo any yaqoolooo aamannaa wa hum la yuftanoon", english: "Do men think that they will be left alone on saying, \"We believe\", and that they will not be tested", romanUrdu: "Kya logon ne yeh samajh rakkha hai ke woh bas itna kehne par chodh diye jayenge ke “hum iman laaye” aur unko aazmaya na jayega" },
    { number: 3, arabic: "وَلَقَدْ فَتَنَّا ٱلَّذِينَ مِن قَبْلِهِمْ ۖ فَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُوا۟ وَلَيَعْلَمَنَّ ٱلْكَٰذِبِينَ", transliteration: "Walaqad fatanna allatheena min qablihim falayaAAlamanna Allahu allatheena sadaqoo walayaAAlamanna alkathibeena", transliterationB: "Wa laqad fatannal lazeena min qablihim fala ya'lamannal laahul lazeena sadaqoo wa la ya'lamannal kaazibeen", english: "We did test those before them, and Allah will certainly know those who are true from those who are false", romanUrdu: "Halaanke hum un sab logon ki aazmaish kar chuke hain jo insey pehle guzre hain. Allah ko to zaroor yeh dekhna hai ke sacchey kaun hain aur jhootey kaun" },
    { number: 4, arabic: "أَمْ حَسِبَ ٱلَّذِينَ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ أَن يَسْبِقُونَا ۚ سَآءَ مَا يَحْكُمُونَ", transliteration: "Am hasiba allatheena yaAAmaloona alssayyiati an yasbiqoona saa ma yahkumoona", transliterationB: "Am hasibal lazeena ya'maloonas sayyiaati any yasbiqoonaa; saaa'a maa yahkumoon", english: "Do those who practise evil think that they will get the better of Us? Evil is their judgment", romanUrdu: "Aur kya woh log jo buri harkatein kar rahey hain yeh samajh baithey hain ke woh humse baazi le jayenge? Bada galat hukum hai jo woh laga rahey hain" },
    { number: 5, arabic: "مَن كَانَ يَرْجُوا۟ لِقَآءَ ٱللَّهِ فَإِنَّ أَجَلَ ٱللَّهِ لَءَاتٍۢ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Man kana yarjoo liqaa Allahi fainna ajala Allahi laatin wahuwa alssameeAAu alAAaleemu", transliterationB: "Man kaana yarjoo liqaaa 'allaahi fa inna ajalal laahi laaat; wa Huwass Sameeul 'Aleem", english: "For those whose hopes are in the meeting with Allah (in the Hereafter, let them strive); for the term (appointed) by Allah is surely coming and He hears and knows (all things)", romanUrdu: "Jo koi Allah se milne ki tawakku (umeed) rakhta ho (usey maloom hona chahiye ke) Allah ka muqarrar kiya hua waqt aane hi wala hai. Aur Allah sab kuch sunta aur jaanta hai" },
    { number: 6, arabic: "وَمَن جَٰهَدَ فَإِنَّمَا يُجَٰهِدُ لِنَفْسِهِۦٓ ۚ إِنَّ ٱللَّهَ لَغَنِىٌّ عَنِ ٱلْعَٰلَمِينَ", transliteration: "Waman jahada fainnama yujahidu linafsihi inna Allaha laghaniyyun AAani alAAalameena", transliterationB: "Wa man jaahada fainnamaa yujaahidu linafsih; innal laaha laghaniyyun 'anil 'aalameen", english: "And if any strive (with might and main), they do so for their own souls: for Allah is free of all needs from all creation", romanUrdu: "Jo shaks bhi mujahida (struggle) karega apne hi bhale ke liye karega. Allah yaqeenan duniya jahan walon se be-niyaz(free of want) hai" },
    { number: 7, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَنَجْزِيَنَّهُمْ أَحْسَنَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ", transliteration: "Waallatheena amanoo waAAamiloo alssalihati lanukaffiranna AAanhum sayyiatihim walanajziyannahum ahsana allathee kanoo yaAAmaloona", transliterationB: "Wallazeena aamanoo wa 'amilus saalihaati lanukaf firanna 'anhum saiyiaatihim wa lanajziyannahum ahsanal lazee kaanoo ya'maloon", english: "Those who believe and work righteous deeds,- from them shall We blot out all evil (that may be) in them, and We shall reward them according to the best of their deeds", romanUrdu: "Aur jo log iman layenge aur neik aamal karenge unki buraiyan hum unse door kardenge aur unhein unke behtareen aamal ki jaza denge" },
    { number: 8, arabic: "وَوَصَّيْنَا ٱلْإِنسَٰنَ بِوَٰلِدَيْهِ حُسْنًۭا ۖ وَإِن جَٰهَدَاكَ لِتُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌۭ فَلَا تُطِعْهُمَآ ۚ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Wawassayna alinsana biwalidayhi husnan wain jahadaka litushrika bee ma laysa laka bihi AAilmun fala tutiAAhuma ilayya marjiAAukum faonabbiokum bima kuntum taAAmaloona", transliterationB: "Wa wassainal insaana biwaalidaihi husnanw wa in jaahadaaka litushrika bee maa laisa laka bihee 'ilmun falaa tuti'humaa; ilaiya marji'ukum fa unabbi'ukum bimaa kuntum ta'maloon", english: "We have enjoined on man kindness to parents: but if they (either of them) strive (to force) thee to join with Me (in worship) anything of which thou hast no knowledge, obey them not. Ye have (all) to return to me, and I will tell you (the truth) of all that ye did", romanUrdu: "Humne Insaan ko hidayat ki hai ke apne waldain(parents) ke saath neik sulook karey lekin agar woh tujh par zoar dalein ke tu mere saath kisi aisey (mabood) ko shareek thehraye jisey tu ( mere shareek ki haisiyat se) nahin jaanta to unki itaat na kar. Meri hi taraf tum sabko palat kar aana hai. Phir main tumko bata dunga ke tum kya karte rahey ho" },
    { number: 9, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُدْخِلَنَّهُمْ فِى ٱلصَّٰلِحِينَ", transliteration: "Waallatheena amanoo waAAamiloo alssalihati lanudkhilannahum fee alssaliheena", transliterationB: "Wallazeena aamanoo w a'amilus saalihaati lanudkhilan nahum fis saaliheen", english: "And those who believe and work righteous deeds,- them shall We admit to the company of the Righteous", romanUrdu: "Aur jo log iman laye hongey aur jinhon ne neik aamal kiye hongey unko hum zaroor saliheen mein dakhil karenge" },
    { number: 10, arabic: "وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ فَإِذَآ أُوذِىَ فِى ٱللَّهِ جَعَلَ فِتْنَةَ ٱلنَّاسِ كَعَذَابِ ٱللَّهِ وَلَئِن جَآءَ نَصْرٌۭ مِّن رَّبِّكَ لَيَقُولُنَّ إِنَّا كُنَّا مَعَكُمْ ۚ أَوَلَيْسَ ٱللَّهُ بِأَعْلَمَ بِمَا فِى صُدُورِ ٱلْعَٰلَمِينَ", transliteration: "Wamina alnnasi man yaqoolu amanna biAllahi faitha oothiya fee Allahi jaAAala fitnata alnnasi kaAAathabi Allahi walain jaa nasrun min rabbika layaqoolunna inna kunna maAAakum awalaysa Allahu biaAAlama bima fee sudoori alAAalameena", transliterationB: "Wa minan naasi many yaqoolu aamannaa billaahi faizaaa ooziya fil laahi ja'ala fitnatan naasi ka'azaabil laahi wa la'in jaaa'a nasrum mir Rabbika la yaqoolunna innaa kunnaa ma'akum; awa laisal laahu bi a'lama bimaa fee surdooril 'aalameen", english: "Then there are among men such as say, \"We believe in Allah\"; but when they suffer affliction in (the cause of) Allah, they treat men's oppression as if it were the Wrath of Allah! And if help comes (to thee) from thy Lord, they are sure to say, \"We have (always) been with you!\" Does not Allah know best all that is in the hearts of all creation", romanUrdu: "Logon mein se koi aisa hai jo kehta hai ke hum iman laye Allah par, magar jab woh Allah ke maamle mein sataya gaya to usne logon ki daali hui aazmaish ko Allah ke azaab ki tarah samajh liya. Ab agar tere Rubb ki taraf se fatah-o-nusrat aa gayi to yahi shaks kahega “hum to tumhare saath thay”. kya duniya walon ke dilon ka haal Allah ko ba-khoobi maloom nahin hai" },
    { number: 11, arabic: "وَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَلَيَعْلَمَنَّ ٱلْمُنَٰفِقِينَ", transliteration: "WalayaAAlamanna Allahu allatheena amanoo walayaAAlamanna almunafiqeena", transliterationB: "Wa la ya'lamannal laahul lazeena aamanoo wa la ya'lamannal munaafiqeen", english: "And Allah most certainly knows those who believe, and as certainly those who are Hypocrites", romanUrdu: "Aur Allah ko to zaroor yeh dekhna hi hai ke iman laney waley kaun hain aur munafiq kaun" },
    { number: 12, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ ٱتَّبِعُوا۟ سَبِيلَنَا وَلْنَحْمِلْ خَطَٰيَٰكُمْ وَمَا هُم بِحَٰمِلِينَ مِنْ خَطَٰيَٰهُم مِّن شَىْءٍ ۖ إِنَّهُمْ لَكَٰذِبُونَ", transliteration: "Waqala allatheena kafaroo lillatheena amanoo ittabiAAoo sabeelana walnahmil khatayakum wama hum bihamileena min khatayahum min shayin innahum lakathiboona", transliterationB: "Wa qaalal lazaeena kafaroo lillazeena aamanut tabi'oo sabeelanaa walnahmil khataayaakum wa maa hum bihaamileena min khataa yaahum min shai'in innahum lakaaziboon", english: "And the Unbelievers say to those who believe: \"Follow our path, and we will bear (the consequences) of your faults.\" Never in the least will they bear their faults: in fact they are liars", romanUrdu: "Yeh kaafir log iman laney walon se kehte hain ke tum hamare tareeqe ki pairwi karo aur tumhari khataon (sins) ko hum apne upar le lenge. Halaanke unki khataon mein se kuch bhi woh apne upar lene waley nahin hai, woh qat-an jhoot kehte hain" },
    { number: 13, arabic: "وَلَيَحْمِلُنَّ أَثْقَالَهُمْ وَأَثْقَالًۭا مَّعَ أَثْقَالِهِمْ ۖ وَلَيُسْـَٔلُنَّ يَوْمَ ٱلْقِيَٰمَةِ عَمَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "Walayahmilunna athqalahum waathqalan maAAa athqalihim walayusalunna yawma alqiyamati AAamma kanoo yaftaroona", transliterationB: "Wa la yahmilunna asqaa lahum wa asqaalam ma'a asqaalihim wa la yus'alunna Yawmal Qiyaamati 'ammaa kaanoo yaftaroon", english: "They will bear their own burdens, and (other) burdens along with their own, and on the Day of Judgments they will be called to account for their falsehoods", romanUrdu: "Haan zaroor woh apne bojh bhi uthayenge aur apne bojhon ke saath bahut se dusre bojh bhi. Aur qayamat ke roz yaqeenan unsey in iftara pardaziyon (bohtaan/ fabrication) ki baaz-purs hogi jo woh karte rahey hain" },
    { number: 14, arabic: "وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَلَبِثَ فِيهِمْ أَلْفَ سَنَةٍ إِلَّا خَمْسِينَ عَامًۭا فَأَخَذَهُمُ ٱلطُّوفَانُ وَهُمْ ظَٰلِمُونَ", transliteration: "Walaqad arsalna noohan ila qawmihi falabitha feehim alfa sanatin illa khamseena AAaman faakhathahumu alttoofanu wahum thalimoona", transliterationB: "Wa laqad arsalnaa Noohan ilaa qawmihee falabisa feehim alfa sanatin illaa khamseena 'aaman fa akhazahumut toofaanu wa hum zaalimoon", english: "We (once) sent Noah to his people, and he tarried among them a thousand years less fifty: but the Deluge overwhelmed them while they (persisted in) sin", romanUrdu: "Humne Nooh ko uski qaum ki taraf bheja aur woh pachhas (fifty) kam ek hazaar baras (950 years) unke darmiyan raha. Aakhir e kaar un logon ko toofaan ne aa ghera is haal mein ke woh zaalim thay" },
    { number: 15, arabic: "فَأَنجَيْنَٰهُ وَأَصْحَٰبَ ٱلسَّفِينَةِ وَجَعَلْنَٰهَآ ءَايَةًۭ لِّلْعَٰلَمِينَ", transliteration: "Faanjaynahu waashaba alssafeenati wajaAAalnaha ayatan lilAAalameena", transliterationB: "Fa anjainaahu wa as haabas safeenati wa ja'alnaahaaa Aayatal lil'aalameen", english: "But We saved him and the companions of the Ark, and We made the (Ark) a Sign for all peoples", romanUrdu: "Phir Nooh ko aur kashti walon ko humne bacha liya aur usey duniya walon ke liye ek nishaan e ibrat (lesson) banakar rakh diya" },
    { number: 16, arabic: "وَإِبْرَٰهِيمَ إِذْ قَالَ لِقَوْمِهِ ٱعْبُدُوا۟ ٱللَّهَ وَٱتَّقُوهُ ۖ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Waibraheema ith qala liqawmihi oAAbudoo Allaha waittaqoohu thalikum khayrun lakum in kuntum taAAlamoona", transliterationB: "Wa Ibraheema iz qaala liqawmihi' budul laaha wattaqoohu zaalikum khayrul lakum in kuntum ta'lamoon", english: "And (We also saved) Abraham: behold, he said to his people, \"Serve Allah and fear Him: that will be best for you- If ye understand", romanUrdu: "Aur Ibrahim ko bheja jabke usne apni qaum se kaha “Allah ki bandagi karo aur ussey daro, yeh tumhare liye behtar hai agar tum jano" },
    { number: 17, arabic: "إِنَّمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ أَوْثَٰنًۭا وَتَخْلُقُونَ إِفْكًا ۚ إِنَّ ٱلَّذِينَ تَعْبُدُونَ مِن دُونِ ٱللَّهِ لَا يَمْلِكُونَ لَكُمْ رِزْقًۭا فَٱبْتَغُوا۟ عِندَ ٱللَّهِ ٱلرِّزْقَ وَٱعْبُدُوهُ وَٱشْكُرُوا۟ لَهُۥٓ ۖ إِلَيْهِ تُرْجَعُونَ", transliteration: "Innama taAAbudoona min dooni Allahi awthanan watakhluqoona ifkan inna allatheena taAAbudoona min dooni Allahi la yamlikoona lakum rizqan faibtaghoo AAinda Allahi alrrizqa waoAAbudoohu waoshkuroo lahu ilayhi turjaAAoona", transliterationB: "Innamaa ta'ubdoona min doonil laahi awsaananw-wa takhluqoona ifkaa; innal lazeena ta'budoona min doonil laahi laa yamlikoona lakum rizqan fabtaghoo 'indal laahir rizqa fabtaghoo 'indal laahir rizqa wa'budoohu washkuroo lahooo ilaihi turja'oon", english: "For ye do worship idols besides Allah, and ye invent falsehood. The things that ye worship besides Allah have no power to give you sustenance: then seek ye sustenance from Allah, serve Him, and be grateful to Him: to Him will be your return", romanUrdu: "Tum Allah ko chodh kar jinhein poojh rahey ho woh to mehaz buth (idols/statue/murtiyan) hain aur tum ek jhoot ghadh rahey ho. Dar haqeeqat Allah ke siwa jinki tum parastish karte ho woh tumhein koi rizq bhi dene ka ikhtiyar nahin rakhte. Allah se rizq maango aur usi ki bandagi karo aur uska shukar ada karo. Usi ki taraf tum paltaye janey waley ho" },
    { number: 18, arabic: "وَإِن تُكَذِّبُوا۟ فَقَدْ كَذَّبَ أُمَمٌۭ مِّن قَبْلِكُمْ ۖ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "Wain tukaththiboo faqad kaththaba omamun min qablikum wama AAala alrrasooli illa albalaghu almubeenu", transliterationB: "Wa in tukazziboo faqad kazzaba umamum min qablikum wa maa'alar Rasooli illal balaaghul mubeen", english: "And if ye reject (the Message), so did generations before you: and the duty of the messenger is only to preach publicly (and clearly)", romanUrdu: "Aur agar tum jhutlate ho to tumse pehle bahut si qaumein jhutla chuki hain. Aur Rasool par saaf saaf paighaam pahuncha dene ke siwa koi zimmedari nahin hai.”" },
    { number: 19, arabic: "أَوَلَمْ يَرَوْا۟ كَيْفَ يُبْدِئُ ٱللَّهُ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥٓ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ", transliteration: "Awalam yaraw kayfa yubdio Allahu alkhalqa thumma yuAAeeduhu inna thalika AAala Allahi yaseerun", transliterationB: "Awa lam yaraw kaifa yubdi'ul laahul khalqa summa yu'eeduh; inna zaalika 'alal laahi yaseer", english: "See they not how Allah originates creation, then repeats it: truly that is easy for Allah", romanUrdu: "Kya in logon ne kabhi dekha hi nahin hai ke Allah kis tarah khalq ki ibtida karta hai, phir uska iaada (repeat) karta hai? Yaqeenan yeh [iaada to (to repeat the creation of a thing) ]Allah ke liye aasaan tarr hai" },
    { number: 20, arabic: "قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ بَدَأَ ٱلْخَلْقَ ۚ ثُمَّ ٱللَّهُ يُنشِئُ ٱلنَّشْأَةَ ٱلْءَاخِرَةَ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Qul seeroo fee alardi faonthuroo kayfa badaa alkhalqa thumma Allahu yunshio alnnashata alakhirata inna Allaha AAala kulli shayin qadeerun", transliterationB: "Qul seeroo fil ardi fanzuroo kaifa baa al khalqa summal laahu yunshi''un nash atal Aakhirah; innal laaha 'alaa kulli shai'in Qadeer", english: "Say: \"Travel through the earth and see how Allah did originate creation; so will Allah produce a later creation: for Allah has power over all things", romanUrdu: "Insey kaho ke zameen mein chalo phiro aur dekho ke usney kis tarah khalq ki ibtida ki hai. Phir Allah baar-e-digar bhi zindagi bakshega (recreate life). Yaqeenan Allah har cheez par qaadir hai" },
    { number: 21, arabic: "يُعَذِّبُ مَن يَشَآءُ وَيَرْحَمُ مَن يَشَآءُ ۖ وَإِلَيْهِ تُقْلَبُونَ", transliteration: "YuAAaththibu man yashao wayarhamu man yashao wailayhi tuqlaboona", transliterationB: "Yu'azzibu many yashaaa'u wa yarhamu many yashaaa'; wa ilaihi tuqlaboon", english: "He punishes whom He pleases, and He grants Mercy to whom He pleases, and towards Him are ye turned", romanUrdu: "Jisey chahe saza de aur jispar chahe reham farmaye. Usi ki taraf tum phere janey waley ho" },
    { number: 22, arabic: "وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍۢ", transliteration: "Wama antum bimuAAjizeena fee alardi wala fee alssamai wama lakum min dooni Allahi min waliyyin wala naseerin", transliterationB: "Wa maaa antum bimu'jizeena fil ardi wa laa fissamaaa'i wa maa lakum min doonil laahi minw waliyyinw wa laa naseer", english: "Not on earth nor in heaven will ye be able (fleeing) to frustrate (his Plan), nor have ye, besides Allah, any protector or helper", romanUrdu: "Tum zameen mein aajiz (overpower) karne waley ho na aasmaan mein. Aur Allah se bachane waala koi sarparast aur madadgaar tumhare liye nahin hai" },
    { number: 23, arabic: "وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ ٱللَّهِ وَلِقَآئِهِۦٓ أُو۟لَٰٓئِكَ يَئِسُوا۟ مِن رَّحْمَتِى وَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Waallatheena kafaroo biayati Allahi waliqaihi olaika yaisoo min rahmatee waolaika lahum AAathabun aleemun", transliterationB: "Wallazeena kafaroo bi Aayaatil laahi wa liqaaa'iheee ulaaa'ika ya'isoo mir rahmatee wa ulaaa'ika lahum 'azaabun aleem", english: "Those who reject the Signs of Allah and the Meeting with Him (in the Hereafter),- it is they who shall despair of My Mercy: it is they who will (suffer) a most grievous Penalty", romanUrdu: "Jin logon ne Allah ki aayaat ka aur ussey mulaqaat ka inkar kiya hai woh meri rehmat se mayous ho chuke hain, aur unke liye dardnaak saza hai" },
    { number: 24, arabic: "فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱقْتُلُوهُ أَوْ حَرِّقُوهُ فَأَنجَىٰهُ ٱللَّهُ مِنَ ٱلنَّارِ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Fama kana jawaba qawmihi illa an qaloo oqtuloohu aw harriqoohu faanjahu Allahu mina alnnari inna fee thalika laayatin liqawmin yuminoona", transliterationB: "Famaa kaana jawaaba qawmiheee illaaa an qaaluqtuloohu aw harriqoohu faanjaahul laahu minan naar; inna fee zaalika la Aayaatil laqawminy yu'minoon", english: "So naught was the answer of (Abraham's) people except that they said: \"Slay him or burn him.\" But Allah did save him from the Fire. Verily in this are Signs for people who believe", romanUrdu: "Phir uski qaum ka jawab iske siwa kuch na tha ke unhone kaha “qatal kardo isey ya jalaa daalo isko”. Aakhir e kar Allah ne usey aag se bacha liya. Yaqeenan is mein nishaniyan hain un logon ke liye jo iman laney waley hain" },
    { number: 25, arabic: "وَقَالَ إِنَّمَا ٱتَّخَذْتُم مِّن دُونِ ٱللَّهِ أَوْثَٰنًۭا مَّوَدَّةَ بَيْنِكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ ثُمَّ يَوْمَ ٱلْقِيَٰمَةِ يَكْفُرُ بَعْضُكُم بِبَعْضٍۢ وَيَلْعَنُ بَعْضُكُم بَعْضًۭا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّٰصِرِينَ", transliteration: "Waqala innama ittakhathtum min dooni Allahi awthanan mawaddata baynikum fee alhayati alddunya thumma yawma alqiyamati yakfuru baAAdukum bibaAAdin wayalAAanu baAAdukum baAAdan wamawakumu alnnaru wama lakum min nasireena", transliterationB: "Wa qaala innamat takhaz tum min doonil laahi awsaanam mawaddata bainikum fil hayaatid dunyaa summa yawmal qiyaamati yakfuru ba'dukum biba 'dinw wa yal'anu ba'dukum ba'danw-wa yal'anu ba'dukum ba'danw wa maa waakumun Naaru wa maa lakum min naasireen", english: "And he said: \"For you, ye have taken (for worship) idols besides Allah, out of mutual love and regard between yourselves in this life; but on the Day of Judgment ye shall disown each other and curse each other: and your abode will be the Fire, and ye shall have none to help", romanUrdu: "Aur usne kaha “ tumne duniya ki zindagi mein to Allah ko chodh kar buthon (idols) ko apne darmiyan muhabbat ka zariya bana liya hai magar qayamat ke roz tum ek dusre ka inkar aur ek dusre par laanat karoge. Aur aag tumhara thikana hogi, aur koi tumhara madadgaar na hoga.”" },
    { number: 26, arabic: "۞ فَـَٔامَنَ لَهُۥ لُوطٌۭ ۘ وَقَالَ إِنِّى مُهَاجِرٌ إِلَىٰ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Faamana lahu lootun waqala innee muhajirun ila rabbee innahu huwa alAAazeezu alhakeemu", transliterationB: "Fa aamana lahoo Loot; wa qaala innee mauhajirun ilaa Rabbee innahoo Huwal 'Azeezul Hakeem", english: "But Lut had faith in Him: He said: \"I will leave home for the sake of my Lord: for He is Exalted in Might, and Wise", romanUrdu: "Us waqt Lut ne usko maana(believed) aur Ibrahim ne kaha main apne Rubb ki taraf hijrat(migrate) karta hoon. Woh zabardast hai aur hakeem hai" },
    { number: 27, arabic: "وَوَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ وَجَعَلْنَا فِى ذُرِّيَّتِهِ ٱلنُّبُوَّةَ وَٱلْكِتَٰبَ وَءَاتَيْنَٰهُ أَجْرَهُۥ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ", transliteration: "Wawahabna lahu ishaqa wayaAAqooba wajaAAalna fee thurriyyatihi alnnubuwwata waalkitaba waataynahu ajrahu fee alddunya wainnahu fee alakhirati lamina alssaliheena", transliterationB: "Wa wahabnaa lahoo Ishaaqa wa Ya'Qooba wa ja'alnaa fee zurriyyatihin Nubuwwata wal Kitaaba wa aatainaahu ajrahoo fid dunyaa wa innahoo fil aakhirati laminas saaliheen", english: "And We gave (Abraham) Isaac and Jacob, and ordained among his progeny Prophethood and Revelation, and We granted him his reward in this life; and he was in the Hereafter (of the company) of the Righteous", romanUrdu: "Aur humne usey Ishaaq (Issac) aur yakub (Jacob) (jaisi aulad) inayat farmayi aur uski nasal mein nubuwat aur kitaab rakh di, aur usey duniya mein uska ajar ata kiya aur aakhirat mein woh yaqeenan saaliheen mein se hoga" },
    { number: 28, arabic: "وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ إِنَّكُمْ لَتَأْتُونَ ٱلْفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍۢ مِّنَ ٱلْعَٰلَمِينَ", transliteration: "Walootan ith qala liqawmihi innakum latatoona alfahishata ma sabaqakum biha min ahadin mina alAAalameena", transliterationB: "Wa Lootan iz qaala liqawmiheee innakum laatoonal faahishata maa sabaqakum bihaa min ahadim minal 'aalameen", english: "And (remember) Lut: behold, he said to his people: \"Ye do commit lewdness, such as no people in Creation (ever) committed before you", romanUrdu: "Aur humne Lut ko bheja jabke usne apni qaum se kaha “Tum to woh fahash kaam karte ho jo tumse pehle duniya walon mein se kisi ne nahin kiya hai" },
    { number: 29, arabic: "أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ وَتَقْطَعُونَ ٱلسَّبِيلَ وَتَأْتُونَ فِى نَادِيكُمُ ٱلْمُنكَرَ ۖ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱئْتِنَا بِعَذَابِ ٱللَّهِ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Ainnakum latatoona alrrijala wataqtaAAoona alssabeela watatoona fee nadeekumu almunkara fama kana jawaba qawmihi illa an qaloo itina biAAathabi Allahi in kunta mina alssadiqeena", transliterationB: "A'innakum lataatoonar rijaala wa taqta'oonas sabeela wa taatoona fee naadekumul munkara famaa kaana jawaaba qawmiheee illaaa an qaalu' tinaaa bi'azaabil laahi in kunta minas saadiqeen", english: "Do ye indeed approach men, and cut off the highway?- and practise wickedness (even) in your councils?\" But his people gave no answer but this: they said: \"Bring us the Wrath of Allah if thou tellest the truth", romanUrdu: "Kya tumhara haal yeh hai ke mardon ke paas jatey ho (to satisfy your lust) , aur raahzani (highway robbery) karte ho, aur apni majlison mein burey kaam karte ho?” Phir koi jawab uski qaum ke paas iske siwa na tha ke unhon ne kaha “ le aa Allah ka azaab agar tu saccha hai”" },
    { number: 30, arabic: "قَالَ رَبِّ ٱنصُرْنِى عَلَى ٱلْقَوْمِ ٱلْمُفْسِدِينَ", transliteration: "Qala rabbi onsurnee AAala alqawmi almufsideena", transliterationB: "Qaala Rabbin surnee 'alal qawmil mufsideen", english: "He said: \"O my Lord! help Thou me against people who do mischief", romanUrdu: "Lut ne kaha “Aey mere Rubb, in mufsid (mischievous) logon ke muqable mein meri madad farma”" },
    { number: 31, arabic: "وَلَمَّا جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوٓا۟ إِنَّا مُهْلِكُوٓا۟ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ ۖ إِنَّ أَهْلَهَا كَانُوا۟ ظَٰلِمِينَ", transliteration: "Walamma jaat rusuluna ibraheema bialbushra qaloo inna muhlikoo ahli hathihi alqaryati inna ahlaha kanoo thalimeena", transliterationB: "Wa lammaa jaaa'at Rusulunaaa Ibraaheema bil bushraa qaalooo innaa muhlikoo ahli haazihil qaryati inna ahlahaa kaanoo zaalimeen", english: "When Our Messengers came to Abraham with the good news, they said: \"We are indeed going to destroy the people of this township: for truly they are (addicted to) crime", romanUrdu: "Aur jab hamare faristade (emissaries/messengers) Ibrahim ke paas basharat (khushkhabri) lekar pahunchey to unhon ne ussey kaha “hum is basti ke logon ko halaak karne waley hain, iske log sakht zaalim ho chuke hain.”" },
    { number: 32, arabic: "قَالَ إِنَّ فِيهَا لُوطًۭا ۚ قَالُوا۟ نَحْنُ أَعْلَمُ بِمَن فِيهَا ۖ لَنُنَجِّيَنَّهُۥ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", transliteration: "Qala inna feeha lootan qaloo nahnu aAAlamu biman feeha lanunajjiyannahu waahlahu illa imraatahu kanat mina alghabireena", transliterationB: "Qaala inna feeha Lootaa; qaaloo nahnu a'lamu biman feehaa lanunajjjiyannahoo wa ahlahooo illam ra atahoo kaanat minal ghaabireen", english: "He said: \"But there is Lut there.\" They said: \"Well do we know who is there: we will certainly save him and his following,- except his wife: she is of those who lag behind", romanUrdu: "Ibrahim ne kaha “wahan to Lut maujood hai”. Unhon ne kaha: “Hum khoob jantey hain ke wahan kaun kaun hai. Hum usey aur uski biwi ke siwa uske baaqi ghar waalon ko bacha lenge”. Uski biwi peechey reh janey walon mein se thi" },
    { number: 33, arabic: "وَلَمَّآ أَن جَآءَتْ رُسُلُنَا لُوطًۭا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًۭا وَقَالُوا۟ لَا تَخَفْ وَلَا تَحْزَنْ ۖ إِنَّا مُنَجُّوكَ وَأَهْلَكَ إِلَّا ٱمْرَأَتَكَ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", transliteration: "Walamma an jaat rusuluna lootan seea bihim wadaqa bihim tharAAan waqaloo la takhaf wala tahzan inna munajjooka waahlaka illa imraataka kanat mina alghabireena", transliterationB: "Wa lammaaa an jaaa'at Rusulunaa Lootan seee'a bihim wa daaqa bihim zar'anw wa qaaloo laa takhaf wa laa tahzan innaa munajjooka wa ahlaka illam ra ataka kaanat minal ghaabireen", english: "And when Our Messengers came to Lut, he was grieved on their account, and felt himself powerless (to protect) them: but they said: \"Fear thou not, nor grieve: we are (here) to save thee and thy following, except thy wife: she is of those who lag behind", romanUrdu: "Phir jab hamare faristade (emissaries/messengers) Lut ke paas pahunchey to unki aamad par woh sakht pareshan aur dil tangg hua. Unhon ne kaha “ na daro aur na ranjh karo, hum tumhein aur tumhare ghar walon ko bacha lenge, siwaye tumhari biwi ke jo peechey reh janey walon mein se hai" },
    { number: 34, arabic: "إِنَّا مُنزِلُونَ عَلَىٰٓ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ", transliteration: "Inna munziloona AAala ahli hathihi alqaryati rijzan mina alssamai bima kanoo yafsuqoona", transliterationB: "Innaa munziloona 'alaaa ahli haazihil qaryati rijzam minas samaaa'i bimaa kaanoo yafsuqoon", english: "For we are going to bring down on the people of this township a Punishment from heaven, because they have been wickedly rebellious", romanUrdu: "Hum is basti ke logon par aasmaan se azaab nazil karne waley hain us fisq (evildoing) ke badaulat jo yeh karte rahey hain”" },
    { number: 35, arabic: "وَلَقَد تَّرَكْنَا مِنْهَآ ءَايَةًۢ بَيِّنَةًۭ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Walaqad tarakna minha ayatan bayyinatan liqawmin yaAAqiloona", transliterationB: "Wa laqat taraknaa min haaa aayatam baiyinatal liqawminy ya'qiloon", english: "And We have left thereof an evident Sign, for any people who (care to) understand", romanUrdu: "Aur humne us basti ki ek khuli nishani chodh di hai un logon ke liye jo aqal se kaam letey hain" },
    { number: 36, arabic: "وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ وَٱرْجُوا۟ ٱلْيَوْمَ ٱلْءَاخِرَ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", transliteration: "Waila madyana akhahum shuAAayban faqala ya qawmi oAAbudoo Allaha waorjoo alyawma alakhira wala taAAthaw fee alardi mufsideena", transliterationB: "Wa ilaa Madyana akhaahum Shu'ayban faqaala yaa qawmi'-budul laaha warjul yawmal aakhira wa laa ta'saw fil ardi mufsideen", english: "To the Madyan (people) (We sent) their brother Shu'aib. Then he said: \"O my people! serve Allah, and fear the Last Day: nor commit evil on the earth, with intent to do mischief", romanUrdu: "Aur Madyan ki taraf humne unke bhai Shoaib ko bheja.Usne kaha “Aey meri qaum ke logon, Allah ki bandagi karo aur roz e aakhir ke umeed-waar raho aur zameen mein mufsid ban kar zyadatiyan (mischief) na karte phiro”" },
    { number: 37, arabic: "فَكَذَّبُوهُ فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", transliteration: "Fakaththaboohu faakhathathumu alrrajfatu faasbahoo fee darihim jathimeena", transliterationB: "Fakazzaboohu fa akhazat humur rajfatu fa asbahoo fee daarihim jaasimeen", english: "But they rejected him: Then the mighty Blast seized them, and they lay prostrate in their homes by the morning", romanUrdu: "Magar unhon ne usey jhutla diya. Aakhir e kaar ek sakht zalzaley ne unhein aa liya aur woh apne gharon mein padey ke padey reh gaye" },
    { number: 38, arabic: "وَعَادًۭا وَثَمُودَا۟ وَقَد تَّبَيَّنَ لَكُم مِّن مَّسَٰكِنِهِمْ ۖ وَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ وَكَانُوا۟ مُسْتَبْصِرِينَ", transliteration: "WaAAadan wathamooda waqad tabayyana lakum min masakinihim wazayyana lahumu alshshaytanu aAAmalahum fasaddahum AAani alssabeeli wakanoo mustabsireena", transliterationB: "Wa 'Aadanw wa Samooda wa qat tabaiyana lakum mim masaakinihim wa zaiyana lahumush Shaitaanu a'maalahum fasaddahum 'anis sabeeli wa kaanoo mustabsireen", english: "(Remember also) the 'Ad and the Thamud (people): clearly will appear to you from (the traces) of their buildings (their fate): the Evil One made their deeds alluring to them, and kept them back from the Path, though they were gifted with intelligence and skill", romanUrdu: "Aur Aad o Samood ko humne halaak kiya, tum woh maqamaat dekh chuke ho jahan woh rehte thay. Unke aamal ko shaytaan ne unke liye khushnuma bana diya aur unhein raah e raast se bargashta kardiya, halanke woh hosh-gosh rakhte thay" },
    { number: 39, arabic: "وَقَٰرُونَ وَفِرْعَوْنَ وَهَٰمَٰنَ ۖ وَلَقَدْ جَآءَهُم مُّوسَىٰ بِٱلْبَيِّنَٰتِ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ وَمَا كَانُوا۟ سَٰبِقِينَ", transliteration: "Waqaroona wafirAAawna wahamana walaqad jaahum moosa bialbayyinati faistakbaroo fee alardi wama kanoo sabiqeena", transliterationB: "Wa Qaaroona wa Fir'awna wa haamaana wa laqad jaaa'ahum Moosa bilbaiyinaati fastakbaroo fil ardi wa maa kaanoo saabiqeen", english: "(Remember also) Qarun, Pharaoh, and Haman: there came to them Moses with Clear Signs, but they behaved with insolence on the earth; yet they could not overreach (Us)", romanUrdu: "Aur Qaroon o Firoun o Hamaan ko humne halaak kiya. Moosa unke paas bayyinaat (khuli nishaniyan) lekar aaya magar unhon ne zameen mein apni badayi ka zaam kiya halanke woh sabaqat le janey (qaabu se nikal janey) waley na thay" },
    { number: 40, arabic: "فَكُلًّا أَخَذْنَا بِذَنۢبِهِۦ ۖ فَمِنْهُم مَّنْ أَرْسَلْنَا عَلَيْهِ حَاصِبًۭا وَمِنْهُم مَّنْ أَخَذَتْهُ ٱلصَّيْحَةُ وَمِنْهُم مَّنْ خَسَفْنَا بِهِ ٱلْأَرْضَ وَمِنْهُم مَّنْ أَغْرَقْنَا ۚ وَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "Fakullan akhathna bithanbihi faminhum man arsalna AAalayhi hasiban waminhum man akhathathu alssayhatu waminhum man khasafna bihi alarda waminhum man aghraqna wama kana Allahu liyathlimahum walakin kanoo anfusahum yathlimoona", transliterationB: "Fakullan akhaznaa bizam bihee faminhum man arsalnaa 'alaihi haasibaa; wa minhum man akhazat hus saihatu wa minhum man khasafnaa bihil arda wa minhum man aghraqnaa; wa maa kaanal laahu li yazlimahum wa laakin kaanoo anfusahum yazlimoon", english: "Each one of them We seized for his crime: of them, against some We sent a violent tornado (with showers of stones); some were caught by a (mighty) Blast; some We caused the earth to swallow up; and some We drowned (in the waters): It was not Allah Who injured (or oppressed) them:\" They injured (and oppressed) their own souls", romanUrdu: "Aakhir e kaar har ek ko humne unke gunaah mein pakda. Phir unmein se kisi par humne pathrao (showers of stones) karne wali hawa bheji, aur kisi ko ek zabardast dhamake ne aa liya, aur kisi ko humne zameen mein dhasa diya, aur kisi ko garq (drown) kardiya. Allah unpar zulm karne wala na tha, magar woh khud hi apne upar zulm kar rahey thay" },
    { number: 41, arabic: "مَثَلُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ كَمَثَلِ ٱلْعَنكَبُوتِ ٱتَّخَذَتْ بَيْتًۭا ۖ وَإِنَّ أَوْهَنَ ٱلْبُيُوتِ لَبَيْتُ ٱلْعَنكَبُوتِ ۖ لَوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "Mathalu allatheena ittakhathoo min dooni Allahi awliyaa kamathali alAAankabooti ittakhathat baytan wainna awhana albuyooti labaytu alAAankabooti law kanoo yaAAlamoona", transliterationB: "Masalul lazeenat takhazoo min doonil laahi awliyaaa'a kamasalil 'ankaboot, ittakhazat baitaa; wa inna awhanal buyooti la baitul 'ankaboot; law kaanoo ya'lamoon", english: "The parable of those who take protectors other than Allah is that of the spider, who builds (to itself) a house; but truly the flimsiest of houses is the spider's house;- if they but knew", romanUrdu: "Jin logon ne Allah ko chodh kar dusre sarparast (protectors) bana liye hain unki misaal makhdi (spider) jaisi hai jo apna ek ghar banati hai, aur sab gharon se zyada kamzoor ghar makhdi (spider) ka ghar hi hota hai, Kaash yeh log ilam rakhte" },
    { number: 42, arabic: "إِنَّ ٱللَّهَ يَعْلَمُ مَا يَدْعُونَ مِن دُونِهِۦ مِن شَىْءٍۢ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Inna Allaha yaAAlamu ma yadAAoona min doonihi min shayin wahuwa alAAazeezu alhakeemu", transliterationB: "Innal laaha ya'lamu maa yad'oona min doonihee min shai'; wa Huwal 'Azeezul Hakeem", english: "Verily Allah doth know of (every thing) whatever that they call upon besides Him: and He is Exalted (in power), Wise", romanUrdu: "Yeh log Allah ko chodh kar jis cheez ko bhi pukarte hain Allah usey khoob jaanta hai aur wahi zabardast aur hakeem hai" },
    { number: 43, arabic: "وَتِلْكَ ٱلْأَمْثَٰلُ نَضْرِبُهَا لِلنَّاسِ ۖ وَمَا يَعْقِلُهَآ إِلَّا ٱلْعَٰلِمُونَ", transliteration: "Watilka alamthalu nadribuha lilnnasi wama yaAAqiluha illa alAAalimoona", transliterationB: "Wa tilkal amsaalu nadribuhaa linnaasi wa maa ya'qiluhaaa illal 'aalimoon", english: "And such are the Parables We set forth for mankind, but only those understand them who have knowledge", romanUrdu: "Yeh misalein (examples) hum logon ki fehmaish (understanding) ke liye dete hain, magar unko wahi log samajhte hain jo ilam rakhte waley hain" },
    { number: 44, arabic: "خَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّلْمُؤْمِنِينَ", transliteration: "Khalaqa Allahu alssamawati waalarda bialhaqqi inna fee thalika laayatan lilmumineena", transliterationB: "Khalaqal laahus samaawaati wal arda bilhaqq; inna fee zaalika la aayatal lilmu mineen", english: "Allah created the heavens and the earth in true (proportions): verily in that is a Sign for those who believe", romanUrdu: "Allah ne aasmaano aur zameen ko barhaqq paida kiya hai, dar haqeeqat is mein ek nishani hai ehle iman ke liye" },
    { number: 45, arabic: "ٱتْلُ مَآ أُوحِىَ إِلَيْكَ مِنَ ٱلْكِتَٰبِ وَأَقِمِ ٱلصَّلَوٰةَ ۖ إِنَّ ٱلصَّلَوٰةَ تَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۗ وَلَذِكْرُ ٱللَّهِ أَكْبَرُ ۗ وَٱللَّهُ يَعْلَمُ مَا تَصْنَعُونَ", transliteration: "Otlu ma oohiya ilayka mina alkitabi waaqimi alssalata inna alssalata tanha AAani alfahshai waalmunkari walathikru Allahi akbaru waAllahu yaAAlamu ma tasnaAAoona", transliterationB: "Utlu maaa oohiya ilaika mional Kitaabi wa aqimis Salaata innas Salaata tanhaa 'anil fahshaaa'i wal munkar; wa lazikrul laahi akbar; wal laahu ya'lamu maa tasna'oon", english: "Recite what is sent of the Book by inspiration to thee, and establish regular Prayer: for Prayer restrains from shameful and unjust deeds; and remembrance of Allah is the greatest (thing in life) without doubt. And Allah knows the (deeds) that ye do", romanUrdu: "(Aey Nabi) Tilawat karo is kitaab ki jo tumhari taraf wahee ke zairye se bheji gayi hai. Aur namaz qayam karo, yaqeenan namaz fahash (behayayi) aur burey kaamon se rokti hai. Aur Allah ka zikr issey bhi zyada badi cheez hai. Allah jaanta hai jo kuch tumlog karte ho" },
    { number: 46, arabic: "۞ وَلَا تُجَٰدِلُوٓا۟ أَهْلَ ٱلْكِتَٰبِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ ۖ وَقُولُوٓا۟ ءَامَنَّا بِٱلَّذِىٓ أُنزِلَ إِلَيْنَا وَأُنزِلَ إِلَيْكُمْ وَإِلَٰهُنَا وَإِلَٰهُكُمْ وَٰحِدٌۭ وَنَحْنُ لَهُۥ مُسْلِمُونَ", transliteration: "Wala tujadiloo ahla alkitabi illa biallatee hiya ahsanu illa allatheena thalamoo minhum waqooloo amanna biallathee onzila ilayna waonzila ilaykum wailahuna wailahukum wahidun wanahnu lahu muslimoona", transliterationB: "Wa laa tujaadilooo Ahlal Kitaabi illaa billatee hiya ahsanu illal lazeena zalamoo minhum wa qoolooo aamannaa billazeee unzila ilainaa wa unzila ilaikum wa illaahunna wa illahukum waahidunw-wa nahnu lahoo muslimoon", english: "And dispute ye not with the People of the Book, except with means better (than mere disputation), unless it be with those of them who inflict wrong (and injury): but say, \"We believe in the revelation which has come down to us and in that which came down to you; Our Allah and your Allah is one; and it is to Him we bow (in Islam)", romanUrdu: "Aur ehle kitaab se behas na karo magar umdah tareeqe se, siwaye un logon ke jo un mein se zaalim hon. Aur unsey kaho ke “hum iman laye hain us cheez par bhi jo hamari taraf bheji gayi hai aur us cheez par bhi jo tumhari taraf bheji gayi thi. Hamara khuda aur tumhara khuda ek hi hai aur hum usi ke muslim (farma bardaar) hain”" },
    { number: 47, arabic: "وَكَذَٰلِكَ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ ۚ فَٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يُؤْمِنُونَ بِهِۦ ۖ وَمِنْ هَٰٓؤُلَآءِ مَن يُؤْمِنُ بِهِۦ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلْكَٰفِرُونَ", transliteration: "Wakathalika anzalna ilayka alkitaba faallatheena ataynahumu alkitaba yuminoona bihi wamin haolai man yuminu bihi wama yajhadu biayatina illa alkafiroona", transliterationB: "Wa kazaalika anzalnaaa ilaikal Kitaab; fallazeena aatainaahumul kitaaba yu'minoona bihee wa min haaa'ulaaa'i many yu'minu bih; wa maa yajhadu bi'Aayaatinaa illal kaafiroon", english: "And thus (it is) that We have sent down the Book to thee. So the People of the Book believe therein, as also do some of these (pagan Arabs): and none but Unbelievers reject our signs", romanUrdu: "(Aey Nabi) humne isi tarah tumhari taraf kitaab nazil ki hai. Is liye woh log jinko humne pehle kitaab di thi woh ispar iman latey hain, aur in logon mein se bhi bahut se ispar iman laa rahey hain. Aur hamari aayat ka inkar sirf kaafir hi karte hain" },
    { number: 48, arabic: "وَمَا كُنتَ تَتْلُوا۟ مِن قَبْلِهِۦ مِن كِتَٰبٍۢ وَلَا تَخُطُّهُۥ بِيَمِينِكَ ۖ إِذًۭا لَّٱرْتَابَ ٱلْمُبْطِلُونَ", transliteration: "Wama kunta tatloo min qablihi min kitabin wala takhuttuhu biyameenika ithan lairtaba almubtiloona", transliterationB: "Wa maa kunta tatloo min qablihee min kitaabinw wa laa takhuttubhoo bi yameenika izal lartaabal mubtiloon", english: "And thou wast not (able) to recite a Book before this (Book came), nor art thou (able) to transcribe it with thy right hand: In that case, indeed, would the talkers of vanities have doubted", romanUrdu: "(Aey Nabi) tum issey pehle koi kitaab nahin padte thay aur na apne haath se likhte thay, agar aisa hota to baatil parast log (votaries of falsehood ) shakk mein padh sakte thay" },
    { number: 49, arabic: "بَلْ هُوَ ءَايَٰتٌۢ بَيِّنَٰتٌۭ فِى صُدُورِ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلظَّٰلِمُونَ", transliteration: "Bal huwa ayatun bayyinatun fee sudoori allatheena ootoo alAAilma wama yajhadu biayatina illa alththalimoona", transliterationB: "Bal huwa aayaatum baiyinaatun fee sudooril lazeena ootul 'ilm; wa maa yajhadu bi aayaatinaa illaz zaalimoon", english: "Nay, here are Signs self-evident in the hearts of those endowed with knowledge: and none but the unjust reject Our Signs", romanUrdu: "Dar-asal yeh roshan nishaniyan hain un logon ke dilon mein jinhein ilm baksha gaya hai. Aur hamari aayaat ka inkar nahin karte magar woh jo zaalim hain" },
    { number: 50, arabic: "وَقَالُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَٰتٌۭ مِّن رَّبِّهِۦ ۖ قُلْ إِنَّمَا ٱلْءَايَٰتُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌ", transliteration: "Waqaloo lawla onzila AAalayhi ayatun min rabbihi qul innama alayatu AAinda Allahi wainnama ana natheerun mubeenun", transliterationB: "Wa qaaloo law laaa unzila 'alaihi aayaatum mir Rabbihee qul innamal aayaatu 'indal laahi wa innamaaa ana nazeerum mubeen", english: "Ye they say: \"Why are not Signs sent down to him from his Lord?\" Say: \"The signs are indeed with Allah: and I am indeed a clear Warner", romanUrdu: "Yeh log kehte hain ke “kyun na utari gayi is shaks par nishaniyan iske Rubb ki taraf se?” kaho “Nishaniyan to Allah ke paas hain aur main sirf khabardar karne wala hoon khol khol kar”" },
    { number: 51, arabic: "أَوَلَمْ يَكْفِهِمْ أَنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ يُتْلَىٰ عَلَيْهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَرَحْمَةًۭ وَذِكْرَىٰ لِقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Awalam yakfihim anna anzalna AAalayka alkitaba yutla AAalayhim inna fee thalika larahmatan wathikra liqawmin yuminoona", transliterationB: "Awa lam yakfihim annaaa anzalnaa 'alaikal kitaaba yutlaa 'alaikhim; inna fee zaalika larahmatanw wa zikraa liqawminy yu'minoon", english: "And is it not enough for them that we have sent down to thee the Book which is rehearsed to them? Verily, in it is Mercy and a Reminder to those who believe", romanUrdu: "Aur kya in logon ke liye yeh (nishani) kaafi nahin hai ke humne tumpar kitaab nazil ki jo inhein padh kar sunayi jaati hai? Dar haqeeqat is mein rehmat hai aur naseehat hai un logon ke liye jo iman latey hain" },
    { number: 52, arabic: "قُلْ كَفَىٰ بِٱللَّهِ بَيْنِى وَبَيْنَكُمْ شَهِيدًۭا ۖ يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ ءَامَنُوا۟ بِٱلْبَٰطِلِ وَكَفَرُوا۟ بِٱللَّهِ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", transliteration: "Qul kafa biAllahi baynee wabaynakum shaheedan yaAAlamu ma fee alssamawati waalardi waallatheena amanoo bialbatili wakafaroo biAllahi olaika humu alkhasiroona", transliterationB: "Qul kafaa billaahi bainee wa bainakum shaheedaa; ya'lamu maa fis samaawaati wal ard; wallazeena aamanoo bil baatili wa kafaroo billaahi ulaaa'ika humul khaasiroon", english: "Say: \"Enough is Allah for a witness between me and you: He knows what is in the heavens and on earth. And it is those who believe in vanities and reject Allah, that will perish (in the end)", romanUrdu: "(Aey Nabi) kaho ke “mere aur tumhare darmiyan Allah gawaahi ke liye kaafi hai. Woh aasmaano aur zameen mein sab kuch jaanta hai. Jo log baatil ko maante hain aur Allah se kufr karte hain wahi khasare(nuksan) mein rehne waley hain.”" },
    { number: 53, arabic: "وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ ۚ وَلَوْلَآ أَجَلٌۭ مُّسَمًّۭى لَّجَآءَهُمُ ٱلْعَذَابُ وَلَيَأْتِيَنَّهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", transliteration: "WayastaAAjiloonaka bialAAathabi walawla ajalun musamman lajaahumu alAAathabu walayatiyannahum baghtatan wahum la yashAAuroona", transliterationB: "Wa yasta'jiloonaka bil'azaab; wa law laaa ajalum musammal lajaaa'ahumul 'zaab; wa la yaatiyannahum baghta tanw wa hum laa yash'uroon", english: "They ask thee to hasten on the Punishment (for them): had it not been for a term (of respite) appointed, the Punishment would certainly have come to them: and it will certainly reach them,- of a sudden, while they perceive not", romanUrdu: "Yeh log tumse azaab jaldi laney ka mutalaba karte hain. Agar ek waqt e muqarrar na kardiya gaya hota to inpar azaab aa chuka hota, aur yaqeenan (apne waqt par) woh aa kar rahega achanak, is haal mein ke inhein khabar bhi na hogi" },
    { number: 54, arabic: "يَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَإِنَّ جَهَنَّمَ لَمُحِيطَةٌۢ بِٱلْكَٰفِرِينَ", transliteration: "YastaAAjiloonaka bialAAathabi wainna jahannama lamuheetatun bialkafireena", transliterationB: "Yasta'jiloonak bil'azaab; wa inna Jahannama lamuhee tatum bilkaafireen", english: "They ask thee to hasten on the Punishment: but, of a surety, Hell will encompass the Rejecters of Faith", romanUrdu: "Yeh tumse azaab jaldi laney ka mutalaba karte hain, halaanke jahannum in kafiron ko ghere mein le chuki hai" },
    { number: 55, arabic: "يَوْمَ يَغْشَىٰهُمُ ٱلْعَذَابُ مِن فَوْقِهِمْ وَمِن تَحْتِ أَرْجُلِهِمْ وَيَقُولُ ذُوقُوا۟ مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Yawma yaghshahumu alAAathabu min fawqihim wamin tahti arjulihim wayaqoolu thooqoo ma kuntum taAAmaloona", transliterationB: "Yawma yaghshaahumul 'azaabu min fawqihim wa min tahti arjulim wa yaqoolu zooqoo maa kuntum ta'maloon", english: "On the Day that the Punishment shall cover them from above them and from below them, and (a Voice) shall say: \"Taste ye (the fruits) of your deeds", romanUrdu: "(Aur inhein pata chalega) us roz jabke azaab inhein upar se bhi dhank lega aur paon ke nichey se bhi aur kahega ke ab chakkho mazaa un kartooton ka jo tum karte thay" },
    { number: 56, arabic: "يَٰعِبَادِىَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ أَرْضِى وَٰسِعَةٌۭ فَإِيَّٰىَ فَٱعْبُدُونِ", transliteration: "Ya AAibadiya allatheena amanoo inna ardee wasiAAatun faiyyaya faoAAbudooni", transliterationB: "Yaa 'ibaadiyal lazeena aamanooo inna ardee waasi 'atun fa iyyaaya fa'budoon", english: "O My servants who believe! truly, spacious is My Earth: therefore serve ye Me - (and Me alone)", romanUrdu: "Aey mere bandon jo iman laye ho, meri zameen waseeh hai, pas tum meri hi bandagi baja lao" },
    { number: 57, arabic: "كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۖ ثُمَّ إِلَيْنَا تُرْجَعُونَ", transliteration: "Kullu nafsin thaiqatu almawti thumma ilayna turjaAAoona", transliterationB: "Kullu nafsin zaaa'iqatul mawti summa ilainaa turja'oon", english: "Every soul shall have a taste of death in the end to Us shall ye be brought back", romanUrdu: "Har mutanaffis ko maut ka maza chakhna hai, phir tum sab hamari hi taraf palta kar laye jaogey" },
    { number: 58, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُبَوِّئَنَّهُم مِّنَ ٱلْجَنَّةِ غُرَفًۭا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ نِعْمَ أَجْرُ ٱلْعَٰمِلِينَ", transliteration: "Waallatheena amanoo waAAamiloo alssalihati lanubawwiannahum mina aljannati ghurafan tajree min tahtiha alanharu khalideena feeha niAAma ajru alAAamileena", transliterationB: "Wallazeena aamanoo wa 'amilus saalihaati la nubawwi 'annahum minal Jannati ghurafan tajree min tahtihal anhaaru khaalideena feehaa; ni'ma ajrul 'aamileen", english: "But those who believe and work deeds of righteousness - to them shall We give a Home in Heaven,- lofty mansions beneath which flow rivers,- to dwell therein for aye;- an excellent reward for those who do (good)", romanUrdu: "Jo log iman laye hain aur jinhon ne neik amal kiye hain unko hum jannat ki buland o baala imaraton (buildings/palaces) mein rakhenge jinke nichey nehrein behti hongi, wahan woh hamesha rahenge. Kya hi umdah ajar hai amal karne walon ke liye" },
    { number: 59, arabic: "ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", transliteration: "Allatheena sabaroo waAAala rabbihim yatawakkaloona", transliterationB: "Allazeena sabaroo wa 'alaa Rabbihim yatawakkaloon", english: "Those who persevere in patience, and put their trust, in their Lord and Cherisher", romanUrdu: "Un logon ke liye jinhon ne sabr kiya hai aur jo apne Rubb par bharosa karte hain" },
    { number: 60, arabic: "وَكَأَيِّن مِّن دَآبَّةٍۢ لَّا تَحْمِلُ رِزْقَهَا ٱللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Wakaayyin min dabbatin la tahmilu rizqaha Allahu yarzuquha waiyyakum wahuwa alssameeAAu alAAaleemu", transliterationB: "Wa ka ayyim min daaabbatil laa tahmilu riqqahaa; al laahu yarzuquhaa wa iyyaakum; wa Huwas Samee'ul Aleem", english: "How many are the creatures that carry not their own sustenance? It is Allah who feeds (both) them and you: for He hears and knows (all things)", romanUrdu: "Kitne hi jaanwar hain jo apna rizq uthaye nahin phirte, Allah unko rizq deta hai aur tumhara raaziq bhi wahi hai. Woh sab kuch sunnta aur jaanta hai" },
    { number: 61, arabic: "وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ", transliteration: "Walain saaltahum man khalaqa alssamawati waalarda wasakhkhara alshshamsa waalqamara layaqoolunna Allahu faanna yufakoona", transliterationB: "Wa la'in sa altahum man khalaqas samaawaati wal arda wa sakhkharash shamsa wal qamara la yaqoolunnal laahu fa ann yu'fakoon", english: "If indeed thou ask them who has created the heavens and the earth and subjected the sun and the moon (to his Law), they will certainly reply, \"Allah\". How are they then deluded away (from the truth)", romanUrdu: "Agar tum in logon se pucho ke zameen aur aasmaano ko kisne paida kiya hai aur Chand aur Suraj ko kisne musakkhar kar rakkha hai, to zaroor kahenge ke Allah ne, phir yeh kidhar se dhoka kha rahey hain" },
    { number: 62, arabic: "ٱللَّهُ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥٓ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Allahu yabsutu alrrizqa liman yashao min AAibadihi wayaqdiru lahu inna Allaha bikulli shayin AAaleemun", transliterationB: "Allaahu yabsutur rizqa limany yashaaa'u min 'ibaadihee wa yaqdiru lah; innal laaha bikulli shai'in Aleem", english: "Allah enlarges the sustenance (which He gives) to whichever of His servants He pleases; and He (similarly) grants by (strict) measure, (as He pleases): for Allah has full knowledge of all things", romanUrdu: "Allah hi hai jo apne bandon mein se jiska chahta hai rizq kushada (enlarge) karta hai aur jiska chahta hai tangg karta hai. Yaqeenan Allah har cheez ka jaanne wala hai" },
    { number: 63, arabic: "وَلَئِن سَأَلْتَهُم مَّن نَّزَّلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَحْيَا بِهِ ٱلْأَرْضَ مِنۢ بَعْدِ مَوْتِهَا لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْقِلُونَ", transliteration: "Walain saaltahum man nazzala mina alssamai maan faahya bihi alarda min baAAdi mawtiha layaqoolunna Allahu quli alhamdu lillahi bal aktharuhum la yaAAqiloona", transliterationB: "Wa la'in sa altahum man nazzala minas samaaa'e maaa'an fa ahyaa bihil arda mim ba'di mawtihaa la yaqoolunnal laah; qulil hamdu lillah; bal aksaruhum laa ya'qiloon", english: "And if indeed thou ask them who it is that sends down rain from the sky, and gives life therewith to the earth after its death, they will certainly reply, \"Allah!\" Say, \"Praise be to Allah!\" But most of them understand not", romanUrdu: "Aur agar tum insey pucho, kisne aasmaan se pani barsaya aur iske zariye se murda padi hui zameen ko jila uthaya to woh zaroor kahenge Allah ne. Kaho, Alhamdulillah, magar aksar log samajhte nahin hain" },
    { number: 64, arabic: "وَمَا هَٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا لَهْوٌۭ وَلَعِبٌۭ ۚ وَإِنَّ ٱلدَّارَ ٱلْءَاخِرَةَ لَهِىَ ٱلْحَيَوَانُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "Wama hathihi alhayatu alddunya illa lahwun walaAAibun wainna alddara alakhirata lahiya alhayawanu law kanoo yaAAlamoona", transliterationB: "Wa maa haazihil hayaa tud dunyaaa illaa lahwunw-wa la'ib; wa innad Daaral Aakhirata la hiyal ha yawaan; law kaano ya'lamoon", english: "What is the life of this world but amusement and play? but verily the Home in the Hereafter,- that is life indeed, if they but knew", romanUrdu: "Aur yeh duniya ki zindagi kuch nahin hai magar ek khel aur dil ka behlawa. Asal zindagi ka ghar to daar e aakhirat(hereafter) hai, kaash yeh log jaantey" },
    { number: 65, arabic: "فَإِذَا رَكِبُوا۟ فِى ٱلْفُلْكِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ إِذَا هُمْ يُشْرِكُونَ", transliteration: "Faitha rakiboo fee alfulki daAAawoo Allaha mukhliseena lahu alddeena falamma najjahum ila albarri itha hum yushrikoona", transliterationB: "Fa-izaa rakiboo fil fulki da'awul laaha mukhilseena lahud deena falammaa najjaa hum ilal baari izaa hum yushrikoon", english: "Now, if they embark on a boat, they call on Allah, making their devotion sincerely (and exclusively) to Him; but when He has delivered them safely to (dry) land, behold, they give a share (of their worship to others)", romanUrdu: "Jab yeh log kashti par sawaar hotay hain to apne deen ko Allah ke liye khaalis karke ussey dua maangte hain. Phir jab woh unhein bacha kar khushki par le aata hai to yakayak yeh shirk karne lagtey hain" },
    { number: 66, arabic: "لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ وَلِيَتَمَتَّعُوا۟ ۖ فَسَوْفَ يَعْلَمُونَ", transliteration: "Liyakfuroo bima ataynahum waliyatamattaAAoo fasawfa yaAAlamoona", transliterationB: "Li yakfuroo bimaaa aatainaahum wa li yatamatta'oo fasaw fa ya'lamoon", english: "Disdaining ungratefully Our gifts, and giving themselves up to (worldly) enjoyment! But soon will they know", romanUrdu: "Taa-ke Allah ki di hui nijaat par uska kufraan e niyamat karein aur (hayat e duniya ke) mazey lootein. Accha, anqareeb inhein maloom ho jayega" },
    { number: 67, arabic: "أَوَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا حَرَمًا ءَامِنًۭا وَيُتَخَطَّفُ ٱلنَّاسُ مِنْ حَوْلِهِمْ ۚ أَفَبِٱلْبَٰطِلِ يُؤْمِنُونَ وَبِنِعْمَةِ ٱللَّهِ يَكْفُرُونَ", transliteration: "Awalam yaraw anna jaAAalna haraman aminan wayutakhattafu alnnasu min hawlihim afabialbatili yuminoona wabiniAAmati Allahi yakfuroona", transliterationB: "Awalam yaraw annaa ja'alnaa haraman aaminanw wa yutakhattafun naasu min haw lihim; afabil baatili yu'minoona wa bini'matil laahi yakfuroon", english: "Do they not then see that We have made a sanctuary secure, and that men are being snatched away from all around them? Then, do they believe in that which is vain, and reject the Grace of Allah", romanUrdu: "Kya yeh dekhte nahin hain ke humne ek pur-aman haram (sanctuary of safety) bana diya hai, halaanke inke gird-o-pesh log uchak liye jatey hain? Kya phir bhi yeh log baatil ko maante hain aur Allah ki niyamat ka kufraan karte hain" },
    { number: 68, arabic: "وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِٱلْحَقِّ لَمَّا جَآءَهُۥٓ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًۭى لِّلْكَٰفِرِينَ", transliteration: "Waman athlamu mimmani iftara AAala Allahi kathiban aw kaththaba bialhaqqi lamma jaahu alaysa fee jahannama mathwan lilkafireena", transliterationB: "Wa man azlamu mimma nif taraa 'alal laahi kaziban aw kazzaba bilhaqqi lammaa jaaa'ah; alaisa fee jahannama maswal lil kaafireen", english: "And who does more wrong than he who invents a lie against Allah or rejects the Truth when it reaches him? Is there not a home in Hell for those who reject Faith", romanUrdu: "Us shaks se bada zaalim kaun hoga jo Allah par jhoot baandhey ya haqq ko jhutlaye jabke woh uske saamne aa chuka ho? Kya aisey kaafiron ka thikana jahannum hi nahin hai" },
    { number: 69, arabic: "وَٱلَّذِينَ جَٰهَدُوا۟ فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا ۚ وَإِنَّ ٱللَّهَ لَمَعَ ٱلْمُحْسِنِينَ", transliteration: "Waallatheena jahadoo feena lanahdiyannahum subulana wainna Allaha lamaAAa almuhsineena", transliterationB: "Wallazeena jaahadoo feenaa lanahdiyannahum subulana; wa innal laaha lama'al muhsineen", english: "And those who strive in Our (cause),- We will certainly guide them to our Paths: For verily Allah is with those who do right", romanUrdu: "Jo log hamari khatir mujahida(strive) karenge unhein hum apne raaste dikhayenge, aur yaqeenan Allah neikukaron(who do good) hi ke saath hai" }
  ]
};
